const promptRow = $input.first().json;
const project = $('Load Project Data').first().json.data;
const input = $('Normalize Input').first().json;
const design = project.design_option || {};
const briefing = project.briefing || {};

const prompt_user = `Proyecto: ${project.project_name}
Tipo: ${project.project_type} (${project.property_type})
Superficie: ${project.property_area_m2} m2
Budget total: ${project.budget_target || '?'} EUR

Nivel domotica solicitado: ${input.level}
Ecosistema preferido: ${input.ecosystem_pref}

DESIGN:
${design.title || '-'}
${design.description || '-'}
Notas tecnicas: ${design.technical_notes || '-'}

BRIEFING:
${briefing.summary || '-'}
Objetivos: ${JSON.stringify(briefing.objectives || [])}
Estancias afectadas: ${JSON.stringify(briefing.rooms_affected || [])}
Estilo cliente: ${JSON.stringify(briefing.style_preferences || {})}

Genera la propuesta de domotica en JSON segun el schema. Responde SOLO el JSON, sin texto adicional.`;

return [{ json: {
  agent_name: 'agent_home_automation',
  prompt_system: promptRow.content,
  prompt_user: prompt_user,
  model: promptRow.model_recommended || 'gpt-4o',
  temperature: promptRow.temperature !== null ? Number(promptRow.temperature) : 0.3,
  project_id: project.project_id,
  next_version: project.next_version,
  level: input.level,
  ecosystem_pref: input.ecosystem_pref
}}];

const llm = $input.first().json;
let text = llm.text || llm.content || '';
text = text.replace(/^```(?:json)?\s*/i,'').replace(/```\s*$/i,'').trim();
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(_) {} }
}
if (!parsed) {
  parsed = {
    ecosystem: 'no_recommendation',
    level: 'basico',
    devices_recommended: [],
    preinstall_requirements: [],
    estimated_cost_devices_eur: null,
    estimated_cost_install_eur: null,
    estimated_total_eur: null,
    rationale: 'LLM no devolvio JSON valido. Texto: ' + text.substring(0,200),
    warnings: ['parse_failure']
  };
}
const num = v => v===null||v===undefined||v===''?null:Number(v);
return [{ json: {
  ecosystem: parsed.ecosystem || 'no_recommendation',
  level: parsed.level || 'basico',
  devices_recommended: Array.isArray(parsed.devices_recommended) ? parsed.devices_recommended : [],
  preinstall_requirements: Array.isArray(parsed.preinstall_requirements) ? parsed.preinstall_requirements : [],
  estimated_cost_devices_eur: num(parsed.estimated_cost_devices_eur),
  estimated_cost_install_eur: num(parsed.estimated_cost_install_eur),
  estimated_total_eur: num(parsed.estimated_total_eur),
  rationale: parsed.rationale || '',
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  llm_model: llm.model || 'gpt-4o',
  llm_tokens_in: llm.tokens_in || null,
  llm_tokens_out: llm.tokens_out || null,
  llm_cost_usd: llm.cost_estimated || null
}}];

parameters.query:
INSERT INTO home_automation_proposals (
  project_id, version, ecosystem, level, devices_recommended, preinstall_requirements,
  estimated_cost_devices_eur, estimated_cost_install_eur, estimated_total_eur,
  rationale, warnings, llm_model, llm_tokens_in, llm_tokens_out, llm_cost_usd
) VALUES (
  $1::uuid, $2::int, $3, $4, $5::jsonb, $6::jsonb,
  $7::numeric, $8::numeric, $9::numeric,
  $10, $11::jsonb, $12, $13::int, $14::int, $15::numeric
) RETURNING id, version, ecosystem, level, estimated_total_eur;

