const inserted = $input.first().json;
const raw = $('Parse Response').first().json;
const project = $('Load Project Data').first().json.data;
const devices = (raw.devices_recommended || []).map(d => '<tr><td>' + (d.room||'?') + '</td><td>' + (d.device_type||'?') + '</td><td>' + (d.name||'?') + (d.notes ? '<br><small style=\"color:#7f8c8d\">' + d.notes + '</small>' : '') + '</td><td>' + (d.qty||1) + ' x ' + (d.unit_price_eur||'?') + ' = <b>' + (d.total_eur||'?') + ' EUR</b></td></tr>').join('');
const preinstall = (raw.preinstall_requirements || []).map(r => '<li>' + (r.critical ? '<b style=\"color:#e74c3c\">[CRITICO]</b> ' : '') + (r.room ? '<b>' + r.room + '</b>: ' : '') + r.description + '</li>').join('');
const warns = (raw.warnings || []).map(w => '<li>' + w + '</li>').join('');
const html = `<div style=\"font-family:Arial,sans-serif;max-width:720px;margin:0 auto\">
<h2 style=\"color:#2c3e50\">Propuesta de domotica generada</h2>
<h3 style=\"color:#7f8c8d\">${project.project_name}</h3>
<table style=\"width:100%;border-collapse:collapse;margin:16px 0\">
  <tr><td style=\"padding:6px;background:#f3f4f6\"><b>Ecosistema</b></td><td style=\"padding:6px\">${raw.ecosystem}</td></tr>
  <tr><td style=\"padding:6px;background:#f3f4f6\"><b>Nivel</b></td><td style=\"padding:6px\">${raw.level}</td></tr>
  <tr><td style=\"padding:6px;background:#f3f4f6\"><b>Dispositivos</b></td><td style=\"padding:6px\">${raw.estimated_cost_devices_eur || '?'} EUR</td></tr>
  <tr><td style=\"padding:6px;background:#f3f4f6\"><b>Instalacion</b></td><td style=\"padding:6px\">${raw.estimated_cost_install_eur || '?'} EUR</td></tr>
  <tr><td style=\"padding:6px;background:#f3f4f6\"><b>TOTAL</b></td><td style=\"padding:6px\"><b>${raw.estimated_total_eur || '?'} EUR</b></td></tr>
</table>
<p><b>Justificacion:</b> ${raw.rationale}</p>
<h3>Dispositivos recomendados</h3>
<table border=\"1\" cellpadding=\"6\" cellspacing=\"0\" style=\"border-collapse:collapse;font-size:13px\"><thead><tr style=\"background:#f3f4f6\"><th>Estancia</th><th>Tipo</th><th>Modelo</th><th>Coste</th></tr></thead><tbody>${devices}</tbody></table>
<h3 style=\"color:#e67e22\">Preinstalacion EN OBRA</h3>
<ul>${preinstall}</ul>
${warns ? '<p style=\"background:#fff8e1;padding:10px;border-left:4px solid #fece00\"><b>Avisos:</b><ul>' + warns + '</ul></p>' : ''}
<p style=\"font-size:11px;color:#95a5a6\">Proposal ID: ${inserted.id}, version ${inserted.version}.</p>
</div>`;
return [{ json: { html_body: html, project_name: project.project_name, ecosystem: raw.ecosystem, total: raw.estimated_total_eur } }];
